module RefModule(DATA_IN, SHIFT_LEFT, DATA_OUT);
input [7:0] DATA_IN;
input SHIFT_LEFT;
output reg [7:0] DATA_OUT;
  wire [7:0] _tap_DATA_IN = DATA_IN & {8{1'b1}};


always @(*) begin
    if (SHIFT_LEFT)
        DATA_OUT = DATA_IN << 1;
    else
        DATA_OUT = DATA_IN >> 1;
end

endmodule
